using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public int Status { get; set; }

    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }

    [MaxLength(200)]
    public string RecipientName { get; set; } = string.Empty;

    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db, IHttpContextAccessor httpContextAccessor) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        var email = httpContextAccessor.HttpContext?.User?.Identity?.Name ?? string.Empty;
        return await db.Shipments
            .Where(s => s.CustomerEmail == email)
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = (int)status;
            if (status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
            await db.SaveChangesAsync();
        }
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}

