@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2 class="mb-4">Dispatcher Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Filter by tracking # or destination…"
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments…</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match your filter.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover align-middle">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Recipient</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.RecipientName</td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width:160px"
                                    value="@s.Status"
                                    @onchange="(e) => OnStatusChanged(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status" selected="@(status == s.Status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments => shipments?.Where(s =>
    {
        if (!string.IsNullOrWhiteSpace(filterStatus) && Enum.TryParse<ShipmentStatus>(filterStatus, out var fs) && s.Status != fs)
            return false;
        if (!string.IsNullOrWhiteSpace(filterText))
        {
            var term = filterText.Trim();
            return s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.RecipientName.Contains(term, StringComparison.OrdinalIgnoreCase);
        }
        return true;
    }) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2 class="mb-4">Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number…"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @(searching ? "Searching…" : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && result is null)
{
    <div class="alert alert-warning">No shipment found for tracking number <strong>@searchedNumber</strong>.</div>
}

@if (result is not null)
{
    <div class="card shadow-sm">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@result.TrackingNumber</strong>
            <span class="badge @StatusBadgeClass(result.Status) fs-6">@result.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@result.Description</dd>
                        <dt>Recipient</dt>
                        <dd>@result.RecipientName</dd>
                        <dt>Origin</dt>
                        <dd>@result.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@result.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@result.ShippedDate.ToString("MMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>@result.EstimatedDelivery.ToString("MMM dd, yyyy")</dd>
                        @if (result.ActualDelivery.HasValue)
