        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number…"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @(searching ? "Searching…" : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && result is null)
{
    <div class="alert alert-warning">No shipment found for tracking number <strong>@searchedNumber</strong>.</div>
}

@if (result is not null)
{
    <div class="card shadow-sm">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@result.TrackingNumber</strong>
            <span class="badge @StatusBadgeClass(result.Status) fs-6">@result.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@result.Description</dd>
                        <dt>Recipient</dt>
                        <dd>@result.RecipientName</dd>
                        <dt>Origin</dt>
                        <dd>@result.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@result.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@result.ShippedDate.ToString("MMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>@result.EstimatedDelivery.ToString("MMM dd, yyyy")</dd>
                        @if (result.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd>@result.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h4>My Shipments</h4>

@if (myShipments is null)
{
    <p><em>Loading your shipments…</em></p>
}
else if (!myShipments.Any())
{
    <p class="text-muted">You have no shipments on file.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped align-middle">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in myShipments)
                {
                    <tr role="button" @onclick="() => SelectShipment(s)">
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Destination</td>
                        <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private bool searching;
    private bool searched;
    private ShipmentDto? result;
    private List<ShipmentDto>? myShipments;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetMyShipmentsAsync();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searching = true;
        searched = false;

        searchedNumber = trackingNumber.Trim();
        result = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);

        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private void SelectShipment(ShipmentDto shipment)
    {
        result = shipment;
        trackingNumber = shipment.TrackingNumber;
        searchedNumber = shipment.TrackingNumber;
        searched = true;
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
